from flask import Blueprint, request, jsonify
from flask_login import login_required, current_user
from models import db, User

profile_bp = Blueprint('profile', __name__)

@profile_bp.route('/api/profile', methods=['PUT'])
@login_required
def update_profile():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    # Define allowed fields for regular users
    user_allowed_fields = {'email', 'username'}
    
    # Define privileged fields that should never be mass-assigned by users
    privileged_fields = {'account_type', 'credits', 'referral_code', 'verified_status'}
    
    # Get the user object - ensure we're only updating the current user's profile
    user = User.query.get(current_user.id)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    # Verify object-level authorization - user can only update their own profile
    if user.id != current_user.id:
        return jsonify({'error': 'Unauthorized'}), 403
    
    updated_fields = []
    errors = []
    
    # Process only allowed fields for regular users
    for field in data.keys():
        if field in privileged_fields:
            errors.append(f'Field "{field}" cannot be modified by users')
            continue
            
        if field not in user_allowed_fields:
            errors.append(f'Field "{field}" is not allowed')
            continue
        
        # Validate and update allowed fields
        if field == 'email':
            email = data[field]
            if not email or '@' not in email:
                errors.append('Invalid email format')
                continue
            # Check if email is already taken by another user
            existing_user = User.query.filter(User.email == email, User.id != current_user.id).first()
            if existing_user:
                errors.append('Email already in use')
                continue
            user.email = email
            updated_fields.append('email')
            
        elif field == 'username':
            username = data[field]
            if not username or len(username) < 3:
                errors.append('Username must be at least 3 characters')
                continue
            # Check if username is already taken by another user
            existing_user = User.query.filter(User.username == username, User.id != current_user.id).first()
            if existing_user:
                errors.append('Username already in use')
                continue
            user.username = username
            updated_fields.append('username')
    
    if updated_fields:
        try:
            db.session.commit()
            return jsonify({
                'message': 'Profile updated successfully',
                'updated_fields': updated_fields,
                'errors': errors if errors else None
            }), 200
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': 'Failed to update profile'}), 500
    else:
        return jsonify({
            'message': 'No fields were updated',
            'errors': errors
        }), 400